#include <bits/stdc++.h>
using namespace std;
int max_3(int x,int y,int z){
    return max(x,max(y,z));
}
int main(){
    int a,b,c;
    cin>>a>>b>>c;
    int v=max_3(a,b,c); 
    float m=float(max_3(a,b,c))/float((max_3(a+b,b,c)*max_3(a,b,b+c)));
    printf("%.3f",m);
    return 0;
}
